#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw * 4;
    vec3 dx = ( GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );
    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
    vec2 uv_bg = mix(vUvOriginal,vUv,1) + vec2(dx.x,dy.x)*uTexSize.zw*4;
    ret.x = GetPixel(uv_bg).x  - (GetPixel(uv_bg).x - GetBlur3(uv_bg).x)*0.02 - 0.008
            +(texture(sampler_noise_lq, dither_uv).xyz-0.5) *0.1 - texture(sampler_fc_main, vUv).z*16;

// there 2 channels unused, see? - hav fun :P

    ret.y = texture(sampler_fc_main, vUv).y - ret.x*0.0076;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vUv = 0.5 + (vUv-0.5)*0.88;
    vec2 d = uTexSize.zw*4;
    vec3 dx = ( GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );

//    vec2 uv_dy = vUv + vec2(dy.y,-dx.y)*0.2*rad_hq;
//    vec3 c1 = GetBlur1(uv_dy).y;

    float grad_y = length(vec2(dx.y,dy.y));
    vec3 c2 = grad_y*0.8;

    vec3 emboss = (dx - dy*0.2)*0.8 + 0.5;

    vec2 uv_light1 = 1-(vec2(q4,q8)*vec2(1,-1) + vec2(0,1));
    vec3 light1_dy = 1.04- pow(length( vUv + vec2(dx.y,dy.y)*2 - uv_light1),0.35);
    vec3 light1_dx = 1.04- pow(length( vUv + vec2(dx.x,dy.x)*2 - uv_light1),0.35);


    vec3 plastic = mix(0,light1_dy*2,c2*4);

ret = -plastic*0 + emboss.y*0.3 + light1_dy*0.5;
ret = GetPixel(vUv).y*ret*2;
ret = mix(GetPixel(vUv - vec2(dy.x,-dx.x)*0.2 + vec2(dx.y,dy.y)*0.2).x*(vec3(0,0,2)+light1_dy*vec3(2,1,-2)),
mix(hue_shader,vec3(2,0.8,0),GetPixel(vUv - vec2(dx.z,dy.z)*0.06 + vec2(dx.y,dy.y)*0.3).z*16),pow(ret,2));

  fragColor = ret;
}
